#include <sys/wait.h>
#include <unistd.h>
#include <stdio.h>

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // Child process
 printf("Child executing, PID: %d\n", getpid());
 sleep(2);
 _exit(42); // Exit with code 42
 } else if (pid > 0) {
 // Parent process
 int status;
 pid_t child_pid = waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("Child %d exited with code: %d\n", 
 child_pid, WEXITSTATUS(status));
 }
 }
 return 0;
}

#include <sys/wait.h>
#include <unistd.h>
#include <stdio.h>
#include <errno.h>

int main() {
 pid_t pids[3];

 // Create 3 children
 for (int i = 0; i < 3; i++) {
 pid_t pid = fork();
 if (pid == 0) {
 sleep(i + 1); // Different sleep times
 _exit(i + 1); // Exit with 1, 2, 3
 }
 pids[i] = pid;
 }

 // Parent polls for children
 int children_left = 3;
 while (children_left > 0) {
 int status;
 pid_t pid = waitpid(-1, &status, WNOHANG);

 if (pid > 0) {
 // Child reaped
 if (WIFEXITED(status)) {
 printf("Child %d exited with code %d\n",
 pid, WEXITSTATUS(status));
 }
 children_left--;
 } else if (pid == 0) {
 // No child terminated yet
 printf("No child terminated, doing other work...\n");
 sleep(1);
 } else if (pid == -1 && errno == ECHILD) {
 // No more children
 break;
 }
 }
 return 0;
}

#include <sys/wait.h>
#include <unistd.h>
#include <stdio.h>

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // First child - creates its own group
 setpgid(0, 0); // Become leader of new group
 pid_t grandchild = fork();
 if (grandchild == 0) {
 // Grandchild in new process group
 sleep(1);
 _exit(99);
 }
 // Wait for grandchild in same group
 int status;
 waitpid(-getpid(), &status, 0); // Wait for group
 _exit(50);
 } 

 // Parent waits for any child in its group
 int status;
 waitpid(-getpid(), &status, 0); // Wait for children in same PGID

 if (WIFEXITED(status)) {
 printf("Child exited with: %d\n", WEXITSTATUS(status));
 }
 return 0;
}

#include <sys/wait.h>
#include <unistd.h>
#include <stdio.h>
#include <signal.h>

void check_status(int status) {
 if (WIFEXITED(status)) {
 printf("Normal exit, code: %d\n", WEXITSTATUS(status));
 }
 else if (WIFSIGNALED(status)) {
 printf("Killed by signal: %d\n", WTERMSIG(status));
 }
 else if (WIFSTOPPED(status)) {
 printf("Stopped by signal: %d\n", WSTOPSIG(status));
 }
 else if (WIFCONTINUED(status)) {
 printf("Continued execution\n");
 }
}

int main() {
 pid_t pid = fork();
 if (pid == 0) {
 // Child - could be terminated by signal
 abort(); // Generates SIGABRT
 }

 int status;
 waitpid(pid, &status, 0);
 check_status(status);
 return 0;
}
